REQUIRED = {'case_id', 'docs', 'expected_top', 'metric', 'query', 'version'}
REJECT = 'REJECT_EMBEDDING_RANK'

def assess(record: dict) -> str:
    absent = sorted(REQUIRED - record.keys())
    if absent:
        return "MISSING:" + ",".join(absent)
    contract_ok = not (min(record["docs"], key=lambda k: sum(a*b for a,b in zip(record["query"],record["docs"][k]))) == record["expected_top"])
    return "PASS" if contract_ok else REJECT

valid_fx = {"case_id": 'CASO-PUN-048-1A', **{'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}}
adverse_fx = {"case_id": 'CASO-PUN-048-1A', **{'query': [1.0, 0.0], 'docs': {'d1': [0.8, 0.2], 'd2': [0.1, 0.9]}, 'metric': 'dot', 'version': 'emb-v2', 'expected_top': 'd1'}}
partial_fx = dict(valid_fx)
partial_fx.pop('expected_top', None)
print(assess(valid_fx), assess(adverse_fx), assess(partial_fx))

